// Transform GitHub issues into a format suitable for Notion sync
const issues = $input.all();
const results = [];

for (const item of issues) {
  const issue = item.json;

  // Map GitHub labels to categories
  const labels = (issue.labels || []).map(l => l.name || l);
  const isFeature = labels.some(l => l.includes('feature') || l.includes('enhancement'));
  const isBug = labels.some(l => l.includes('bug'));
  const isDoc = labels.some(l => l.includes('documentation') || l.includes('docs'));

  // Map GitHub state to Notion status
  let notionStatus = 'Backlog';
  if (issue.state === 'closed') {
    notionStatus = 'Done';
  } else if (issue.assignee) {
    notionStatus = 'In Progress';
  }

  // Determine type
  let type = 'Task';
  if (isFeature) type = 'Feature';
  if (isBug) type = 'Bug';
  if (isDoc) type = 'Documentation';

  results.push({
    json: {
      github_number: issue.number,
      github_id: issue.id,
      title: issue.title,
      body: (issue.body || '').substring(0, 500),
      state: issue.state,
      notion_status: notionStatus,
      type: type,
      labels: labels,
      github_url: issue.html_url,
      assignee: issue.assignee?.login || 'unassigned',
      milestone: issue.milestone?.title || null,
      created_at: issue.created_at,
      updated_at: issue.updated_at,
      closed_at: issue.closed_at
    }
  });
}

return results;

// Compare GitHub issues with existing Notion items
// Determine which need to be created vs updated
const githubIssues = $('Transform Issue Data').all();
const notionItems = $('Get Existing Notion Items').all();

// Build a map of existing Notion items by GitHub issue number
const notionMap = {};
for (const item of notionItems) {
  const props = item.json.properties || item.json;
  const ghNumber = props['GitHub Number']?.number || props.github_number;
  if (ghNumber) {
    notionMap[ghNumber] = {
      page_id: item.json.id,
      title: props.Name?.title?.[0]?.plain_text || '',
      status: props.Status?.select?.name || ''
    };
  }
}

const toCreate = [];
const toUpdate = [];

for (const issue of githubIssues) {
  const ghNum = issue.json.github_number;
  if (notionMap[ghNum]) {
    // Issue exists in Notion — check if update needed
    const existing = notionMap[ghNum];
    if (existing.status !== issue.json.notion_status || existing.title !== issue.json.title) {
      toUpdate.push({
        json: {
          ...issue.json,
          notion_page_id: existing.page_id,
          action: 'update'
        }
      });
    }
  } else {
    // New issue — needs to be created
    toCreate.push({
      json: {
        ...issue.json,
        action: 'create'
      }
    });
  }
}

// Output both sets
return [...toCreate, ...toUpdate];

// Log sync summary
const allItems = $input.all();
const created = allItems.filter(i => i.json.action === 'create').length;
const updated = allItems.filter(i => i.json.action === 'update').length;

console.log(`GitHub-Notion Sync complete: ${created} created, ${updated} updated`);

return [{
  json: {
    sync_time: new Date().toISOString(),
    items_created: created,
    items_updated: updated,
    total_processed: allItems.length
  }
}];
